module RefModule(CLK, RST, ENABLE, Q);
input CLK, RST, ENABLE;
output reg [1:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Q <= 2'b00;
    else if (ENABLE)
        Q <= Q + 1'b1;
end

endmodule
